#include <iostream>

namespace math {
    int add(int a, int b);
    int subtract(int a, int b);
    int multiply(int a, int b);
    int divide(int a, int b);
}

int main() {
    int a, b;
    std::cin >> a >> b;
    std::cout << "Sum: "      << math::add(a, b)      << "\n";
    std::cout << "Diff: "     << math::subtract(a, b) << "\n";
    std::cout << "Product: "  << math::multiply(a, b) << "\n";
    std::cout << "Quotient: " << math::divide(a, b)   << "\n";
    return 0;
}

namespace math {
    int add(int a, int b) {
        return a + b;
    }
    int subtract(int a, int b) {
        return a - b;
    }
    int multiply(int a, int b) {
        return a * b;
    }
    int divide(int a, int b) {
        return a / b;
    }
}

