solution_code:
#include <iostream>

int volume(int l, int w, int h);
int surfaceArea(int l, int w, int h);

int main() {
    int l, w, h;
    std::cin >> l >> w >> h;
    std::cout << "Volume: "  << volume(l, w, h)     << "\n";
    std::cout << "Surface: " << surfaceArea(l, w, h) << "\n";
    return 0;
}

int volume(int l, int w, int h) {
    return l * w * h;
}

int surfaceArea(int l, int w, int h) {
    return 2 * (l * w + l * h + w * h);
}
